export const RECOMMENDED_DATA = Object.entries(WORD_BANKS).reduce((acc, [year, weeks]) => {
  acc[year] = weeks.map((theme, i) => ({
    id: `y${year}-w${i + 1}`,
    name: `Year ${year} - Week ${i + 1} (${theme.theme})`,
    year: parseInt(year),
    week: i + 1,
    words: [...theme.words]
  }));
  return acc;
}, {});

